    {
      "id": "FR11",
      "description": "System jest zaprojektowany w sposób skalowalny, umożliwiający obsługę rosnącej liczby użytkowników, specjalistów i rezerwacji bez degradacji wydajności."
    },
    {
      "id": "FR12",
      "description": "Administrator może generować raporty dotyczące liczby rezerwacji, anulowań, obłożenia grafiku specjalistów oraz aktywności użytkowników w zadanym przedziale czasowym."
    }
  ]
}

